// Near-verbatim TS port of the approved prototype (asb/route-waypoints.js).
//
// Three tiers (priority order):
//   1. ecdis    — exact stored geometry (the 20 master voyage plans the distance
//                 matrix was computed from), symmetric, solid line + "ECDIS" tag.
//   2. corridor — BFS across a sea-zone adjacency graph, stitch chokepoint chains
//                 (Bosphorus/Suez/Bab-el-Mandeb/Hormuz…), dekink + centripetal
//                 Catmull-Rom smooth, dashed line + "est." tag.
//   3. arc      — same-zone/unknown → gently bowed quadratic arc (never a chord).
//
// The DB grows the exact tier: migration …000860 seeds port_routes; as more pairs
// are stored, more lines draw exact. (This bundled ECDIS keeps the map standalone;
// swap to a DB read of port_routes when you want it server-sourced.)
export type LL = [number, number];
export interface RouteGeo { pts: LL[]; nm: number | null; exact: boolean; source: "ecdis" | "corridor" | "arc" }

