const ADJ: Record<string, string[]> = {};
Object.keys(EDGES).forEach((k) => {
  const [a, b] = k.split("|");
  (ADJ[a] = ADJ[a] || []).push(b);
  (ADJ[b] = ADJ[b] || []).push(a);
});
function edgeChain(from: string, to: string): LL[] | null {
  if (EDGES[from + "|" + to]) return EDGES[from + "|" + to].slice();
  if (EDGES[to + "|" + from]) return EDGES[to + "|" + from].slice().reverse();
  return null;
}
function zonePath(from: string, to: string): string[] | null {
  if (from === to) return [from];
  if (!ADJ[from] || !ADJ[to]) return null;
  const q: string[][] = [[from]];
  const seen = new Set([from]);
  while (q.length) {
    const path = q.shift()!;
    const last = path[path.length - 1];
    for (const nx of ADJ[last] || []) {
      if (seen.has(nx)) continue;
      const np = path.concat(nx);
      if (nx === to) return np;
      seen.add(nx);
      q.push(np);
    }
  }
  return null;
}

function haversineNm(a: LL, b: LL): number {
  const R = 3440.065;
  const toR = Math.PI / 180;
  const dLat = (b[0] - a[0]) * toR, dLon = (b[1] - a[1]) * toR;
  const la1 = a[0] * toR, la2 = b[0] * toR;
  const h = Math.sin(dLat / 2) ** 2 + Math.cos(la1) * Math.cos(la2) * Math.sin(dLon / 2) ** 2;
  return 2 * R * Math.asin(Math.min(1, Math.sqrt(h)));
}
function pathNm(pts: LL[]): number {
  let s = 0;
  for (let i = 1; i < pts.length; i++) s += haversineNm(pts[i - 1], pts[i]);
  return s;
}
function dedupe(pts: LL[], eps: number): LL[] {
  const out: LL[] = [pts[0]];
  for (let i = 1; i < pts.length; i++) {
    const p = pts[i], q = out[out.length - 1];
    if (Math.abs(p[0] - q[0]) > eps || Math.abs(p[1] - q[1]) > eps) out.push(p);
  }
  return out;
}
function turnAt(pts: LL[], i: number): number {
  const a = pts[i - 1], b = pts[i], c = pts[i + 1];
  const h1 = Math.atan2(b[0] - a[0], b[1] - a[1]);
  const h2 = Math.atan2(c[0] - b[0], c[1] - b[1]);
  let d = (Math.abs(h2 - h1) * 180) / Math.PI;
  if (d > 180) d = 360 - d;
  return d;
}
// A real voyage never reverses >~100° at one vertex; drop the worst offending
// interior control point until monotone. Endpoints (the ports) are never removed.
function dekink(pts: LL[], maxTurnDeg: number): LL[] {
  if (pts.length < 3) return pts;
  const work = pts.slice();
  for (let guard = 0; guard < work.length + 4; guard++) {
    let worstI = -1, worst = maxTurnDeg;
    for (let i = 1; i < work.length - 1; i++) {
      const t = turnAt(work, i);
      if (t > worst) { worst = t; worstI = i; }
    }
    if (worstI < 0) break;
    work.splice(worstI, 1);
  }
  return work;
}
// Centripetal Catmull-Rom (alpha = 0.5) — no overshoot/loops on uneven spacing.
function smooth(pts: LL[], perSeg: number): LL[] {
  if (pts.length < 3) return pts;
  const a = 0.5;
  const tj = (ti: number, pi: LL, pj: LL) => Math.pow(Math.max(Math.hypot(pj[0] - pi[0], pj[1] - pi[1]), 1e-6), a) + ti;
  const P = (i: number) => pts[Math.max(0, Math.min(pts.length - 1, i))];
  const res: LL[] = [];
  for (let i = 0; i < pts.length - 1; i++) {
    const p0 = P(i - 1), p1 = P(i), p2 = P(i + 1), p3 = P(i + 2);
    const t0 = 0, t1 = tj(t0, p0, p1), t2 = tj(t1, p1, p2), t3 = tj(t2, p2, p3);
    for (let s = 0; s < perSeg; s++) {
      const t = t1 + (s / perSeg) * (t2 - t1);
      const pt = [0, 1].map((d) => {
        const A1 = ((t1 - t) / (t1 - t0)) * p0[d] + ((t - t0) / (t1 - t0)) * p1[d];
        const A2 = ((t2 - t) / (t2 - t1)) * p1[d] + ((t - t1) / (t2 - t1)) * p2[d];
        const A3 = ((t3 - t) / (t3 - t2)) * p2[d] + ((t - t2) / (t3 - t2)) * p3[d];
        const B1 = ((t2 - t) / (t2 - t0)) * A1 + ((t - t0) / (t2 - t0)) * A2;
        const B2 = ((t3 - t) / (t3 - t1)) * A2 + ((t - t1) / (t3 - t1)) * A3;
        return ((t2 - t) / (t2 - t1)) * B1 + ((t - t1) / (t2 - t1)) * B2;
      }) as LL;
      res.push(pt);
    }
  }
  res.push(pts[pts.length - 1]);
  return res;
}
function arc(a: LL, b: LL): LL[] {
  const mid: LL = [(a[0] + b[0]) / 2, (a[1] + b[1]) / 2];
  const dx = b[1] - a[1], dy = b[0] - a[0];
  const len = Math.hypot(dx, dy) || 1;
  const off = Math.min(len * 0.16, 4);
  const ctrl: LL = [mid[0] + (dx / len) * off, mid[1] - (dy / len) * off];
  const out: LL[] = [];
  for (let t = 0; t <= 1.0001; t += 1 / 24) {
    const u = 1 - t;
    out.push([u * u * a[0] + 2 * u * t * ctrl[0] + t * t * b[0], u * u * a[1] + 2 * u * t * ctrl[1] + t * t * b[1]]);
  }
  return out;
}

export interface RouteOpts {
  polCode?: string | null; podCode?: string | null;
  polLL?: LL | null; podLL?: LL | null;
  polZone?: string | null; podZone?: string | null;
}
export function routeGeometry(opts: RouteOpts): RouteGeo | null {
  const { polCode, podCode, polLL, podLL, polZone, podZone } = opts || {};
  if (polCode && podCode) {
    const fwd = ECDIS[polCode + "|" + podCode];
    if (fwd) {
      const pts = fwd.pts.slice();
      if (polLL) pts[0] = polLL;
      if (podLL) pts[pts.length - 1] = podLL;
      return { pts: smooth(dedupe(pts, 0.004), 6), nm: fwd.nm, exact: true, source: "ecdis" };
    }
    const rev = ECDIS[podCode + "|" + polCode];
    if (rev) {
      const pts = rev.pts.slice().reverse();
      if (polLL) pts[0] = polLL;
      if (podLL) pts[pts.length - 1] = podLL;
      return { pts: smooth(dedupe(pts, 0.004), 6), nm: rev.nm, exact: true, source: "ecdis" };
    }
  }
  if (!polLL || !podLL) return null;
  const zp = polZone && podZone ? zonePath(polZone, podZone) : null;
  if (zp && zp.length >= 2) {
    let chain: LL[] = [polLL];
    for (let i = 0; i < zp.length - 1; i++) {
      const seg = edgeChain(zp[i], zp[i + 1]);
      if (seg) chain = chain.concat(seg);
    }
    chain.push(podLL);
    chain = dedupe(chain, 0.05);
    chain = dekink(chain, 100);
    if (chain.length >= 3) {
      return { pts: smooth(chain, 10), nm: Math.round(pathNm(chain)), exact: false, source: "corridor" };
    }
  }
  return { pts: arc(polLL, podLL), nm: Math.round(pathNm([polLL, podLL])), exact: false, source: "arc" };
}
